import unittest

class TestSolution(unittest.TestCase):
    def test_basic_example(self):
        d = {"A001": "Alice", "B002": "Bob", "C003": "Charlie"}
        expected = {"Alice": "A001", "Bob": "B002", "Charlie": "C003"}
        self.assertEqual(invert_lookup(d), expected)

    def test_country_codes(self):
        d = {"FR": "France", "DE": "Germany"}
        expected = {"France": "FR", "Germany": "DE"}
        self.assertEqual(invert_lookup(d), expected)

    def test_empty_dict(self):
        self.assertEqual(invert_lookup({}), {})

    def test_hidden_single_entry(self):
        self.assertEqual(invert_lookup({"x": "y"}), {"y": "x"})

    def test_hidden_numeric_values(self):
        d = {"a": 1, "b": 2, "c": 3}
        expected = {1: "a", 2: "b", 3: "c"}
        self.assertEqual(invert_lookup(d), expected)

    def test_hidden_course_codes(self):
        d = {"101": "Math", "102": "Science", "103": "English"}
        expected = {"Math": "101", "Science": "102", "English": "103"}
        self.assertEqual(invert_lookup(d), expected)

    def test_hidden_values_with_spaces(self):
        d = {"US": "United States", "UK": "United Kingdom"}
        expected = {"United States": "US", "United Kingdom": "UK"}
        self.assertEqual(invert_lookup(d), expected)

    def test_hidden_original_unchanged(self):
        d = {"a": "x", "b": "y"}
        result = invert_lookup(d)
        self.assertEqual(d, {"a": "x", "b": "y"})
        self.assertEqual(result, {"x": "a", "y": "b"})

if __name__ == '__main__':
    unittest.main()
